onClick:
{{ 
  Insertar_Catalogo.run()
  .then(() => {
    // 1. Muestra un mensaje de éxito verde
    showAlert('Ítem añadido al catálogo correctamente', 'success');

    // 2. Refresca la tabla para que veas la nave aparecer al instante
    // (Asegúrate de que 'Leer_Catalogo' sea el nombre real de la consulta que llena tu tabla)
    return Leer_Catalogo.run(); 
  })
  .then(() => {
    // 3. Limpia las casillas para que queden listas para el siguiente registro
    resetWidget('inp_id');
    resetWidget('inp_nombre');
    resetWidget('inp_item_volumen');
    resetWidget('chk_nueva_categoria');
    resetWidget('inp_nueva_categoria');
  })
  .catch((error) => {
    // Si realmente hay un error, te lo muestra limpiamente
    showAlert('Error: ' + error.message, 'error');
  })
}}
